

CREATE TABLE `tb_aboutus` (
  `id` int(20) NOT NULL AUTO_INCREMENT,
  `section_1` longtext COLLATE utf8_unicode_ci,
  `section_2` longtext COLLATE utf8_unicode_ci,
  `section_3` longtext COLLATE utf8_unicode_ci,
  `section_4` longtext COLLATE utf8_unicode_ci,
  `meta_title` text COLLATE utf8_unicode_ci,
  `meta_desc` text COLLATE utf8_unicode_ci,
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `deleted_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=2 DEFAULT CHARSET=utf8 COLLATE=utf8_unicode_ci;


INSERT INTO tb_aboutus (id, section_1, section_2, section_3, section_4, meta_title, meta_desc, created_at, updated_at, deleted_at) VALUES ('1','{"banner_image":"1642405012.jpg","title":"About Us","description":"We provide extensive medical operations to outbound and inbound patients, and we are quite proud of our staff\'s accomplishments. We are all working together to assist our patients in their recovery","banner_btn_name":"Fix Appointment","banner_btn_link":"book-your-appointment"}','{"aboutus_image":"1648714533-9300.jpg","aboutus_title":"About Dr. Aravind\'s IVF Fertility & Pregnancy Centre","aboutus_description":"<p class=\"text-justify\">Even in this modern-day, there are still many people who do not have children. They were unaware that Dr. Aravind\'s IVF Fertility &amp; Pregnancy Centre could provide a solution. The purpose of Dr. Aravind\'s IVF Fertility &amp; Pregnancy Centre&nbsp;was to help childless couples experience the joys of motherhood. To realise their objective, Dr. Aravind\'s IVF Fertility &amp; Pregnancy Centre&nbsp;has sophisticated fertility treatments, world-class facilities, and a highly skilled team of fertility doctors.<\/p>\r\n         <p class=\"text-justify\">Dr. Aravind\'s IVF Fertility &amp; Pregnancy Centre has been at the forefront of offering the best in technology and innovative fertility treatments to people for the past three decades. It\'s no surprise that Dr. Aravind\'s IVF Fertility &amp; Pregnancy Centre&nbsp;has been named the top fertility in India for her excellent attention and dedication to the cause.<\/p>"}','["1","2"]','["1","2","3","4","5","6","7","8","10","11","51","52"]','Best Fertility Center Near me | Dr. Aravind\'s IVF Fertility & Pregnancy Centre','Dr. Aravind\'s IVF Fertility & Pregnancy Centre has been at the forefront of offering the best in technology and innovative fertility treatments to people for the past three decades','2023-02-17 14:25:58','2022-01-17 07:36:52','2022-01-17 07:36:52');


