  `meta_desc` text COLLATE utf8_unicode_ci,
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `deleted_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=2 DEFAULT CHARSET=utf8 COLLATE=utf8_unicode_ci;


INSERT INTO tb_awards (id, section_1, section_2, meta_title, meta_desc, created_at, updated_at, deleted_at) VALUES ('1','{"banner_image":"1642423022.jpg","title":"Awards & recognition","description":"In the field of fertility, Iswarya IVF Centre has won several awards.","banner_btn_name":"Fix Appointment","banner_btn_link":"book-your-appointment"}','["1","2","3","4"]','Dr. Aravind\'s IVF Fertility & Pregnancy Centre Award and Recognition','In the field of fertility, Dr. Aravind\'s IVF Fertility & Pregnancy Centre has won several awards. Fix your appointment to be successful parenthood.','2022-10-12 05:51:02','2022-01-17 12:37:02','2022-01-17 12:37:02');


