  `banner_title` varchar(300) COLLATE utf8_unicode_ci DEFAULT NULL,
  `banner_description` text COLLATE utf8_unicode_ci,
  `careers` longtext COLLATE utf8_unicode_ci,
  `doctors_and_embryologists` longtext COLLATE utf8_unicode_ci,
  `meta_title` text COLLATE utf8_unicode_ci,
  `meta_desc` text COLLATE utf8_unicode_ci,
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `deleted_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=2 DEFAULT CHARSET=utf8 COLLATE=utf8_unicode_ci;


INSERT INTO tb_careerspage (id, banner_image, banner_title, banner_description, careers, doctors_and_embryologists, meta_title, meta_desc, created_at, updated_at, deleted_at) VALUES ('1','1642489530-61554830.jpg','Careers','When it comes to remaining healthy physically, emotionally, and financially, we value your health and wellbeing. We\'ll be there for you every step of the way.','<p>Dr. Aravind\'s IVF Fertility &amp; Pregnancy Centre provides a great opportunity for professionals to further their careers. We are ideally suited for those who are willing to take on challenges and be part of a company that is a game-changer in the healthcare industry. We invite you to be part of our successful team and join us on this memorable journey that will also give a great boost to your career.</p><p>For further details, please contact:</p><p>Email : info@draravindsivf.com</p>','<p>With the aim of strengthening our clinical team of doctors and embryologists, as well as facilitating growth for the organisation, Iswarya IVF Fertility is looking to partner with skilled and dedicated professionals from the industry.</p><p>By partnering with Dr. Aravind\'s IVF Fertility &amp; Pregnancy Centre, you can be a part of an international healthcare brand, and gain access to state-of-the-art medical facilities<br></p><p>Email : info@draravindsivf.com<br></p>','Careers at Dr. Aravind\'s IVF Fertility & Pregnancy Centre','Dr. Aravind\'s IVF Fertility & Pregnancy Centre provides a great opportunity for professionals to further their careers. Join our team.','2022-01-18 07:05:30','2022-01-18 07:05:30','2022-01-18 07:05:30');


