INSERT INTO tb_expertslist_page (id, section_1, section_2, section_3, meta_title, meta_desc, created_at, updated_at, deleted_at) VALUES ('1','{"banner_image":"16426451652149.jpg","title":"Fertility Experts","description":"Dr. Aravind\'s IVF Fertility & Pregnancy Centre provides a wealth of fertility information. Iswarya has earned a number of prizes in recognition of its efforts. Their strong desire to turn infertility into fertility is the reason they were given those honors to Iswarya.","banner_btn_name":"Fix Appointment","banner_btn_link":"book-your-appointment"}','1,2','3,4,5,6','Best Fertility Specialist Center in India | Dr. Aravind\'s IVF Fertility & Pregnancy Centre','Dr. Aravind\'s IVF Fertility & Pregnancy Centre has sophisticated fertility treatments, world-class facilities, and a highly skilled team of fertility doctors. Fix your appointment to be a successful parenthood.','2022-01-20 02:19:25','2022-01-20 02:19:25','2022-01-20 02:19:25');


