CREATE TABLE `tb_faq_details` (
  `id` int(20) NOT NULL AUTO_INCREMENT,
  `title` text COLLATE utf8_unicode_ci,
  `description` longtext COLLATE utf8_unicode_ci,
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `deleted_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=8 DEFAULT CHARSET=utf8 COLLATE=utf8_unicode_ci;


INSERT INTO tb_faq_details (id, title, description, created_at, updated_at, deleted_at) VALUES ('1','When should I opt for IVF?','<p>IVF was originally developed for women with blocked tubes or missing fallopian tubes and it is still the procedure of choice for these situations. It is also used when other conditions are present, including endometriosis, male factor infertility and unexplained infertility in which no medical cause for infertility can be found. Our experts will review your history and help to guide you to the treatment and diagnostic procedures that are most appropriate for you.</p>','2022-03-17 05:53:49','2022-03-17 05:53:49','2022-03-17 05:53:49');

INSERT INTO tb_faq_details (id, title, description, created_at, updated_at, deleted_at) VALUES ('2','How to detect ovulation cycle with irregular periods?','<p> You need to make a special effort to detect your ovulation cycle if you are suffering from irregular menses. You can consider using an ovulation detector and then take your next step ahead so that the chances of positive results are high. If still, you are not getting the result you are looking for, then you can always consider connecting with a specialist at Iswarya IVF Fertility &amp; Pregnancy Centre for better guidance. 
</p>','2022-03-30 09:03:47','2022-03-30 09:03:47','2022-03-30 09:03:47');

INSERT INTO tb_faq_details (id, title, description, created_at, updated_at, deleted_at) VALUES ('3','What are the different fertility treatment options?','<p>There are many treatment options to deal with fertility issues. Your case is assessed by the specialist and accordingly, the best treatment options are considered. Some of the options that are considered by the specialists are surgery to repair any issues with the reproductive system, IVF, Intracytoplasmic sperm injection, and more. You can consider connecting with the specialists at Iswarya IVF Fertility &amp; Pregnancy Centre and get a better understanding of the treatments as per your needs.</p>','2022-03-30 09:05:41','2022-03-30 09:05:41','2022-03-30 09:05:41');

INSERT INTO tb_faq_details (id, title, description, created_at, updated_at, deleted_at) VALUES ('4','How to prevent miscarriage?','<p>

                                There is always a way that can help you prevent a failure of pregnancy. All you need to do is to take good care of yourself and your baby. For the same, you must consider opting for regular prenatal care and avoid all the risk factors that lead to miscarriage. You must seek medical attention whenever you are having any kind of issue to avoid the same at the earliest. Iswarya IVF- Fertility &amp; Pregnancy can certainly help you with it. You can always reach out to our specialist and take all the assistance you need to prevent pregnancy failure. 



                            </p>','2022-03-30 09:07:30','2022-03-30 09:07:30','2022-03-30 09:07:30');

INSERT INTO tb_faq_details (id, title, description, created_at, updated_at, deleted_at) VALUES ('5','When should you see a doctor about your irregular menses?','<p>

                                It\'s better to connect with a gynecologist as and when you are trying to get pregnant, but the results aren\'t going your way because of irregular periods. Running some tests can help them get an understanding of where the problem lies and help you with proper medication that can help you conceive without any hassle. If  you are looking for assistance, you can always consider connecting with specialists at Iswarya IVF Fertility &amp; Pregnancy Centre. 



                            </p>','2022-03-30 09:08:14','2022-03-30 09:08:14','2022-03-30 09:08:14');

INSERT INTO tb_faq_details (id, title, description, created_at, updated_at, deleted_at) VALUES ('6','Which vaccine to prefer Covaxin or Covid-shield?','<p>

                               Dr. Reshma says “Both are equally effective and each individual above the age of 18 can go for available vaccinations either Covaxin or Covid-Shield in their nearby camps and hospitals. Generally women under infertility treatment and pregnancy are on LMWH injection. It is highly recommended that they should stop the LMWH injection for a day or two and then get Covid vaccination. With most of the common questions from pregnant women being answered by the doctor, she concludes the session by suggesting that patients with diabetes, seizures, hyper tension, asthma, heart problemand patients with gynec problems like thyroid, fibroid, PCOS, endometriosis, fibrosis, ovarian cyst can get vaccinated without any worries.



                            </p>','2022-03-30 09:08:59','2022-03-30 09:08:59','2022-03-30 09:08:59');

INSERT INTO tb_faq_details (id, title, description, created_at, updated_at, deleted_at) VALUES ('7','What is in vitro fertilization?','<p>

                               When it comes to In vitro fertilization or IVF, it is one of the fertility treatments popular all around the world. It is actually acknowledged as assisted reproductive technology where both sperm and the egg are administered in a lab. This treatment removes the mature female eggs with the use of a needle and then puts the sperm in it with the use of lab facilities. To know more, you can always consider connecting with the specialists at Iswarya IVF Fertility &amp; Pregnancy Centre.



                            </p>','2022-03-30 09:09:37','2022-03-30 09:09:37','2022-03-30 09:09:37');


