INSERT INTO tb_faq_page (id, banner_section, meta_title, meta_desc, created_at, updated_at, deleted_at) VALUES ('1','{"banner_image":"1647500442.jpg","title":"FAQ","description":"Test description","banner_btn_name":"Fix Appointment","banner_btn_link":"#"}','FAQ at Dr. Aravind\'s IVF Fertility & Pregnancy Centre','Dr. Aravind\'s IVF Fertility & Pregnancy Centre is the best fertility clinic center in India. Our vision is to help childless couples enjoy the joy of parenthood with world-class fertility treatments. Book your appointments now!','2022-10-12 05:53:20','2022-03-17 06:57:12','2022-03-17 06:57:12');


CREATE TABLE `tb_fertility_experts` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `image` varchar(255) COLLATE utf8_unicode_ci NOT NULL,
  `medium_image` varchar(255) COLLATE utf8_unicode_ci NOT NULL,
  `large_image` varchar(255) COLLATE utf8_unicode_ci NOT NULL,
  `name` varchar(255) COLLATE utf8_unicode_ci NOT NULL,
  `position` varchar(255) COLLATE utf8_unicode_ci DEFAULT NULL,
