  `description` longtext COLLATE utf8_unicode_ci,
  `qualification` text COLLATE utf8_unicode_ci NOT NULL,
  `phone_number` varchar(20) COLLATE utf8_unicode_ci NOT NULL,
  `email` varchar(255) COLLATE utf8_unicode_ci NOT NULL,
  `centres` text COLLATE utf8_unicode_ci NOT NULL,
  `overview` text COLLATE utf8_unicode_ci NOT NULL,
  `medical_registration` text COLLATE utf8_unicode_ci NOT NULL,
  `specialization` text COLLATE utf8_unicode_ci NOT NULL,
  `location_consulting_timing` text COLLATE utf8_unicode_ci NOT NULL,
  `membership` text COLLATE utf8_unicode_ci NOT NULL,
  `link` varchar(300) COLLATE utf8_unicode_ci DEFAULT NULL,
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
