INSERT INTO tb_fertility_experts (id, image, medium_image, large_image, name, position, position_2, short_description, description, qualification, phone_number, email, centres, overview, medical_registration, specialization, location_consulting_timing, membership, link, created_at, updated_at, deleted_at) VALUES ('1','1648710401-49371935.jpg','medium_1648710401.jpg','large_1648710401.jpg','Dr. Aravind Chander','Managing Director','Fertility Super specialist','Dr. Aravind Chander completed his MBBS at Annamalai University and acquired the MS(Obstetrics and Gynecology) qualification from Dr. M.G.R. Medical University. He also acquired a Postdoctoral fellowship in reproductive medicine at the Iswarya Fertility Center Institute. His special focus of interest is infertility, laparoscopic surgeries, PGS, and PGD.','<p>After completing his MBBS at Annamalai University, Dr. Aravind Chander acquired the MS(Obstetrics and Gynecology) qualification from Dr. M.G.R. Medical University. He also acquired a Postdoctoral fellowship in reproductive medicine at the Iswarya Fertility Center Institute. His special focus of interest is in fertility, laparoscopic surgeries, PGS, and PGD. He has also been awarded Guinness World Records 2019, India Book of Records 2019, Best IVf Specialist South Ethealth World National Fertility Awards, Best IVF Chain of Hospitals South Ethealth World National Fertility Awards 2019, and Coimbatore City Icon Award Excellence In IVF Fertility Specialty.</p><p>Dr. Aravind Chander has also attended several conferences as a faculty and published several journals on national and international standards. This reflects how passionate towards his work and spends most of his time in the rehabilitation of his patients so that they can lead a healthy life.<br></p>','MBBS, MS (OG), A.R.T ( Singapore ), F.MAS, D.MAS (Germany), M.MAS, F.R.M','+91 90 2013 2013','info@draravindsivf.com','Coimbatore','<li>IUI, IVF, ICSI, IMSI, PICSI, PGD, PGS</li>
<li>Hysteroscopy</li>
<li>Donor Egg</li>
<li>Laparoscopy</li>
