INSERT INTO tb_fertility_experts (id, image, medium_image, large_image, name, position, position_2, short_description, description, qualification, phone_number, email, centres, overview, medical_registration, specialization, location_consulting_timing, membership, link, created_at, updated_at, deleted_at) VALUES ('2','1648711136-25227587.jpg','medium_1648711136.jpg','large_1648711136.jpg','Dr. Reshma Shree A.','Clinical Director','Fertility Super specialist','Dr. Reshma Shri completed her Master\'s in Obstetrics and Gynecology. Her keen area of interest is reproductive medicine. In the process, she completed a Postdoctoral Fellowship in Reproductive Medicine from Dr. M.G.R. Medical University. She has also mastered Minimal Access Surgery and this makes her the most qualified person in the respective field.','<p class="text-justify">Dr. Reshma Shri is a renowned Gynaecologist &amp; Fertility Specialist having years’ experience. She completed her Master\'s in Obstetrics and Gynecology. In the process, she completed a Postdoctoral Fellowship in Reproductive Medicine from Dr. M.G.R. Medical University. She has also mastered Minimal Access Surgery and this makes her the most qualified person in the respective field. With her highest expertise in the treatment of infertility, she has given thousands of couples the joy of parenting. She offers a full range of services for women from adolescence to menopause and she is a one-stop solution for all problems. </p>
<p class="text-justify">Dr. Reshma Shree has been invited as faculty in several conferences. She has published her paper in various international and national journals and also has conducted several CME programs and public forums and many infertility-free camps in Tamil Nadu which has helped thousands of couples. </p>','MBBS, MS - Obstetrics & Gynaecology, FRM, FMAS Fertility Super Specialist, Department of Reproductive Medicine','+91 90 2013 2013','info@draravindsivf.com','','<li>IUI, IVF, ICSI, IMSI, PICSI, PGD, PGS</li>

                    <li>Hysteroscopy</li>

                    <li>Donor Egg</li>

                    <li>Laparoscopy</li>

                    <li>Pregnancy Delivery</li>','<li>TN Medical Council, TN, India Embryo</li>','<li>Infertility</li>

                                <li>

                                    Obstetrics &amp; Gynaecology

                                </li>','','','reshma-shri','2022-03-31 07:18:56','2022-03-31 07:18:56','');

