CREATE TABLE `tb_homepage` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `section_1` text COLLATE utf8_unicode_ci,
  `section_2` text COLLATE utf8_unicode_ci,
  `section_3` text COLLATE utf8_unicode_ci,
  `section_4` text COLLATE utf8_unicode_ci,
  `section_5` text COLLATE utf8_unicode_ci,
  `section_6` text COLLATE utf8_unicode_ci,
  `section_7` text COLLATE utf8_unicode_ci,
  `section_8` text COLLATE utf8_unicode_ci,
  `section_9` longtext COLLATE utf8_unicode_ci,
  `section_10` longtext COLLATE utf8_unicode_ci,
  `section_11` longtext COLLATE utf8_unicode_ci,
  `meta_title` text COLLATE utf8_unicode_ci,
  `meta_desc` text COLLATE utf8_unicode_ci,
  `created_at` datetime NOT NULL ON UPDATE CURRENT_TIMESTAMP,
  `updated_at` datetime NOT NULL,
  `deleted_at` datetime NOT NULL,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=2 DEFAULT CHARSET=utf8 COLLATE=utf8_unicode_ci;


INSERT INTO tb_homepage (id, section_1, section_2, section_3, section_4, section_5, section_6, section_7, section_8, section_9, section_10, section_11, meta_title, meta_desc, created_at, updated_at, deleted_at) VALUES ('1','["1","2"]','["1","2","3","4","5"]','{"spec_title":"Why Choose Us?","spec_description":"Dr. Aravind\'s IVF Fertility & Pregnancy Centre was started with the vision to help childless couples enjoy the joy of parenthood with advanced fertility treatments, world-class infrastructure and highly specialized team of IVF Specialists.","specialities":"[{\"spec_inner_num\":\"70000+\",\"spec_inner_title\":\"IVF Cycles\",\"spec_inner_img_name\":\"16420632835199.png\"},{\"spec_inner_num\":\"20000+\",\"spec_inner_title\":\"New Born Baby\",\"spec_inner_img_name\":\"16420632285937.png\"},{\"spec_inner_num\":\"75%\",\"spec_inner_title\":\"IVF Success rate\",\"spec_inner_img_name\":\"16420632831452.png\"}]"}','{"avail_title":"30 Years of trusted fertility care","avail_desc":"Dr. Aravind\'s IVF Fertility & Pregnancy Centre has many fertility treatment options for couples to consider to help you become pregnant, whats right for you? Your age,health, and family goals are the key ingredients in determining the choices avalable to you.","availabilities":"[{\"avail_sub_title1\":\"75%\",\"avail_sub_title2\":\"IVF SUCCESS RATE\",\"aval_sub_description\":\"Dr. Aravind\'s IVF Fertility & Pregnancy Centre was started with the vision to help childless couples enjoy the joy of parenthood with advanced fertility treatments, world-class infrastructure and highly specialized team of IVF Specialists.\",\"avail_sub_img_name\":\"16420702787536.png\"},{\"avail_sub_title1\":\"70000+\",\"avail_sub_title2\":\"+IVF CYCLES\",\"aval_sub_description\":\"Our practice is put to the test daily earning the continuing trust and respect of our patients. We are proud of our enduring relationships with many individuals who have successfully undergone IVF cycles with us.\",\"avail_sub_img_name\":\"16420702787066.png\"},{\"avail_sub_title1\":\"20000+\",\"avail_sub_title2\":\"BABIES BORN\",\"aval_sub_description\":\"We report our success in terms of live births per transfer. Because protocols are constantly changing and improving, we believe that the live birth rate per transfer most accurately reflects the current performance of us.\",\"avail_sub_img_name\":\"16420702788695.png\"},{\"avail_sub_title1\":\"INDIAS FIRST\",\"avail_sub_title2\":\"IVF CHAIN\",\"aval_sub_description\":\"We are the first IVF chain, throughout the nation, that provides accessible and affordable fertility treatment. We strive to do the most effective treatment options based on your medical history,and diagnosis.\",\"avail_sub_img_name\":\"16420702789011.png\"}]"}','["1","2"]','["113","110","111","112"]','["1","2","3"]','["1","2","3","4"]','{"pioneer_image":"1641918015-3034.png","pioneer_title":"The Pioneer of Dr. Aravind\'s IVF Fertility & Pregnancy Centre","pioneer_name":"Dr. Aravind Chander","pioneer_description":"After completing his MBBS at Annamalai University, Dr. Aravind Chander acquired the MS(Obstetrics and Gynecology) qualification from Dr. M.G.R. Medical University. He also acquired a Postdoctoral fellowship in reproductive medicine at the Iswarya Fertility Center Institute. His special focus of interest is infertility, laparoscopic surgeries, PGS, and PGD.\r\n\r\nHe has also been awarded Guinness World Records 2019, India Book Of Records 2019, Best IVf Specialist South EthealthWorld National Fertility Awards, Best IVF Chain Of Hospitals South EthealthWorld National Fertility Awards 2019, and Coimbatore City Icon Award Excellence In IVF Fertility Specialty.","pioneer_btn_name":"Read More","pioneer_btn_link":"about-us"}','["1","2","3","4","5","6","8","10","11","51","52"]','["1","2","3"]','Best Fertility Clinic Center in India | Dr. Aravind\'s IVF Fertility & Pregnancy Centre','Dr. Aravind\'s IVF Fertility & Pregnancy Centre is the best fertility clinic center in India. Our vision is to help childless couples enjoy the joy of parenthood with world class fertility treatments and having 30+ years of experience. Book your appointments now!','2023-01-21 10:44:12','0000-00-00 00:00:00','0000-00-00 00:00:00');


CREATE TABLE `tb_homepage_banner` (
  `id` int(20) NOT NULL AUTO_INCREMENT,
  `banner_title` text COLLATE utf8_unicode_ci,
  `description` text COLLATE utf8_unicode_ci,
  `image` varchar(300) COLLATE utf8_unicode_ci DEFAULT NULL,
  `btn_title` varchar(300) COLLATE utf8_unicode_ci DEFAULT NULL,
  `url` varchar(300) COLLATE utf8_unicode_ci DEFAULT NULL,
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `deleted_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=3 DEFAULT CHARSET=utf8 COLLATE=utf8_unicode_ci;


INSERT INTO tb_homepage_banner (id, banner_title, description, image, btn_title, url, created_at, updated_at, deleted_at) VALUES ('1','Best Medical Care For You and Your Family','<p>We provide extensive medical operations to outbound and inbound patients, and we are quite proud of our staff\'s accomplishments. We are all working together to assist our patients in their recovery.</p>','1647580715-701698.jpg','Fix Appointment','book-your-appointment','2022-03-18 05:18:35','2022-03-18 05:18:35','2022-03-18 05:18:35');

INSERT INTO tb_homepage_banner (id, banner_title, description, image, btn_title, url, created_at, updated_at, deleted_at) VALUES ('2','','','1647580757-44154689.jpg','','#','2022-03-18 05:19:17','2022-03-18 05:19:17','2022-03-18 05:19:17');


CREATE TABLE `tb_locationdetailpage` (
  `id` int(20) NOT NULL AUTO_INCREMENT,
  `location_id` int(20) DEFAULT NULL,
  `banner_section` longtext COLLATE utf8_unicode_ci,
  `convenient_section` longtext COLLATE utf8_unicode_ci,
  `overview` text COLLATE utf8_unicode_ci,
  `doctors` text COLLATE utf8_unicode_ci,
  `gallery` text COLLATE utf8_unicode_ci,
  `testimonial_section` text COLLATE utf8_unicode_ci,
  `meta_title` text COLLATE utf8_unicode_ci,
  `meta_desc` text COLLATE utf8_unicode_ci,
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `deleted_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=16 DEFAULT CHARSET=utf8 COLLATE=utf8_unicode_ci;


INSERT INTO tb_locationdetailpage (id, location_id, banner_section, convenient_section, overview, doctors, gallery, testimonial_section, meta_title, meta_desc, created_at, updated_at, deleted_at) VALUES ('1','1','{"banner_image":"1647509639.jpg","title":"Our IVF Centre in Ganapathy, Coimbatore","description":"We are well established across the cities of South-India. Find us in your city for successful parenthood.","banner_btn_name":"Fix Appointment","banner_btn_link":"book-your-appointment"}','<li>
                        As one of the most prominent Coimbatore based fertility centers, Iswarya Fertility is here to help you live your dream of becoming a parent. With our experts on board, you can be assured that we will do all we can.
                    </li>
                    <li>
                        The latest treatments have given us the best track record of helping couples with complete success. Our experienced fertility team will design our approach as per the individual\'s need and will analyze the perfect treatment(s) after reviewing everything carefully.

                    </li>
                    <li>So, connect with us now or schedule your appointment online to take your first step towards parenthood </li>','<h4 class="sub-head">Treatments we Offer</h4>
                    <p>Take a look at the wide range of world-class treatments to assist you to conceive:</p>
                    <ul class="flower list-unstyled mb-0">
                    <li>IUI</li>
                    <li>Andrology</li>
                    <li>Natural + OI</li>
                    <li>Surrogacy</li>
                    <li>ICSI</li>
                    <li>PGD</li>
                    <li>IVF</li>
                    <li>Egg Donor</li>
                    <li>PGS</li>
                    <li>Azoospermia</li>
                    <li>IMSI<br><br></li>
                </ul>

                        <h4 class="sub-head">Our Stepped approach to Care</h4>
