CREATE TABLE `tb_locations` (
  `id` int(20) NOT NULL AUTO_INCREMENT,
  `country` varchar(300) COLLATE utf8_unicode_ci DEFAULT NULL,
  `location` varchar(300) COLLATE utf8_unicode_ci DEFAULT NULL,
  `link` varchar(300) COLLATE utf8_unicode_ci DEFAULT NULL,
  `banner_image` varchar(300) COLLATE utf8_unicode_ci DEFAULT NULL,
  `banner_title` varchar(300) COLLATE utf8_unicode_ci DEFAULT NULL,
  `banner_description` text COLLATE utf8_unicode_ci,
  `banner_btn_name` varchar(200) COLLATE utf8_unicode_ci DEFAULT NULL,
  `banner_btn_link` varchar(300) COLLATE utf8_unicode_ci DEFAULT NULL,
  `address_title` varchar(300) COLLATE utf8_unicode_ci DEFAULT NULL,
  `address` text COLLATE utf8_unicode_ci,
  `email` varchar(300) COLLATE utf8_unicode_ci DEFAULT NULL,
  `mobile` varchar(300) COLLATE utf8_unicode_ci DEFAULT NULL,
  `detailpage_link` varchar(300) COLLATE utf8_unicode_ci DEFAULT NULL,
  `convenient_section` longtext COLLATE utf8_unicode_ci,
  `meta_title` text COLLATE utf8_unicode_ci,
  `meta_desc` text COLLATE utf8_unicode_ci,
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `deleted_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`)
