CREATE TABLE `tb_notification` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `userid` int(11) DEFAULT NULL,
  `url` varchar(255) DEFAULT NULL,
  `title` varchar(255) DEFAULT NULL,
  `note` text,
  `created` datetime DEFAULT NULL,
  `icon` char(20) DEFAULT NULL,
  `is_read` enum('0','1') DEFAULT '0',
  `postedBy` int(11) DEFAULT NULL,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=2 DEFAULT CHARSET=latin1;


INSERT INTO tb_notification (id, userid, url, title, note, created, icon, is_read, postedBy) VALUES ('1','1','#','tester','','2017-11-28 14:14:03','','1','1');


CREATE TABLE `tb_page_meta` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `pagename` text NOT NULL,
  `meta_title` text NOT NULL,
  `meta_desc` text NOT NULL,
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  `deleted_at` datetime DEFAULT NULL,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=2 DEFAULT CHARSET=utf8mb4;


INSERT INTO tb_page_meta (id, pagename, meta_title, meta_desc, created_at, updated_at, deleted_at) VALUES ('1','gallerypage','Dr. Aravind\'s IVF Fertility & Pregnancy Centre Gallery','Dr. Aravind\'s IVF Fertility & Pregnancy Centre has been named the top fertility in Tamilnadu for her excellent attention and dedication to the cause. Fix your appointment to be a successful parenthood.','2022-07-23 07:39:35','2022-10-12 00:20:43','');


CREATE TABLE `tb_pages` (
  `pageID` int(11) NOT NULL AUTO_INCREMENT,
  `cid` int(6) DEFAULT NULL,
  `title` varchar(255) DEFAULT NULL,
  `alias` varchar(100) DEFAULT NULL,
  `sinopsis` varchar(250) DEFAULT NULL,
  `note` text,
  `filename` varchar(50) DEFAULT NULL,
  `headline` enum('1','0') DEFAULT NULL,
  `status` enum('enable','disable') DEFAULT 'enable',
  `access` text,
  `allow_guest` enum('0','1') DEFAULT '0',
  `template` enum('frontend','backend') DEFAULT 'frontend',
  `metakey` varchar(255) DEFAULT NULL,
  `metadesc` text,
  `default` enum('0','1') DEFAULT '0',
  `pagetype` enum('page','post') DEFAULT NULL,
  `labels` text,
  `views` int(11) DEFAULT '0',
  `userid` int(11) DEFAULT NULL,
  `thumbnail` varchar(100) DEFAULT NULL,
  `cover` varchar(100) DEFAULT NULL,
  `short_description` text,
  `image` varchar(255) DEFAULT NULL,
  `list_image` varchar(255) DEFAULT NULL,
  `faq_details` longtext,
  `updated` datetime DEFAULT NULL,
  `created` datetime DEFAULT NULL,
  PRIMARY KEY (`pageID`)
) ENGINE=MyISAM AUTO_INCREMENT=118 DEFAULT CHARSET=utf8;


