INSERT INTO tb_situations (id, title, image, link, banner_image, description, created_at, updated_at, deleted_at) VALUES ('1','I want to have a baby some day','1641904057-97157411.png','I-want-to-have-a-baby-some-day','1641904057-50278876.jpg','It\'s great that you are planning to have a baby someday. You need to invest financially and emotionally for the future of your baby\'s health.','0000-00-00 00:00:00','0000-00-00 00:00:00','0000-00-00 00:00:00');

INSERT INTO tb_situations (id, title, image, link, banner_image, description, created_at, updated_at, deleted_at) VALUES ('2','My menses is irregular','1648536817-82036808.jpg','my-menses-is-irregular','1648536817-16365538.jpg','Irregular menses are quite common but can play a role in hampering your dream of starting a family. But, there is always a solution to overcome a problem, and we are here to help you with a few of the FAQs that can give you clarity on how to deal with the situation.','2022-03-29 06:53:37','2022-03-29 06:53:37','2022-03-29 06:53:37');

INSERT INTO tb_situations (id, title, image, link, banner_image, description, created_at, updated_at, deleted_at) VALUES ('3','I have had multiple failure of pregnancies','1648536918-75889127.png','I-have-had-multiple-failure-of-pregnancies','1648536918-73802347.jpg','There are several women who have reported multiple failures of pregnancies, but that doesn\'t make it easier to deal with the same. It requires significant emotional healing and mental toughness to recover from the same. To help you out, we bring you multiple FAQs to recover from the situation.','2022-03-29 06:55:18','2022-03-29 06:55:18','2022-03-29 06:55:18');

INSERT INTO tb_situations (id, title, image, link, banner_image, description, created_at, updated_at, deleted_at) VALUES ('4','I want to understand treatment options','1648537187-2858435.png','I-want-to-understand-treatment-options','1648537187-83287795.jpg','There are many issues related to fertility, and fortunately, there are several treatments related to it. You just need to connect with the specialist to gain a proper understanding of the treatment that can be ideal for your situation and help you with a successful pregnancy.','2022-03-29 06:59:47','2022-03-29 06:59:47','2022-03-29 06:59:47');

INSERT INTO tb_situations (id, title, image, link, banner_image, description, created_at, updated_at, deleted_at) VALUES ('5','I\'m diagnosed with PCOS','1648537289-64287785.jpg','I-m-diagnosed-with-PCOS','1648537289-80220215.jpg','There are several women diagnosed with PCOS so, it is quite common but not easy to deal with if you are thinking about getting pregnant. To make it easy for you, we are here to help you with a few sets of FAQs that can assist you in making your decisions rightly.','2022-03-29 07:01:29','2022-03-29 07:01:29','2022-03-29 07:01:29');


CREATE TABLE `tb_situations_details` (
  `id` int(20) NOT NULL AUTO_INCREMENT,
  `situation_id` int(20) DEFAULT NULL,
  `title` varchar(300) COLLATE utf8_unicode_ci DEFAULT NULL,
  `question` varchar(300) COLLATE utf8_unicode_ci DEFAULT NULL,
  `answer` longtext COLLATE utf8_unicode_ci,
  `image` varchar(300) COLLATE utf8_unicode_ci NOT NULL,
  `created_at` datetime NOT NULL,
  `updated_at` datetime NOT NULL ON UPDATE CURRENT_TIMESTAMP,
  `deleted_at` datetime NOT NULL ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=25 DEFAULT CHARSET=utf8 COLLATE=utf8_unicode_ci;


INSERT INTO tb_situations_details (id, situation_id, title, question, answer, image, created_at, updated_at, deleted_at) VALUES ('1','1','Fertile Window','What else can help you get pregnant Apart from being healthy?','<h2 class="s-head">What else can help you get pregnant Apart from being healthy?</h2>
                                  <p class="text-justify">Timing  plays a big role in pregnancy success. You can only get pregnant in the menstrual cycle during the time of the fertile window. You can check when you are ovulating, and accordingly, you can plan to conceive. The chances of positive results are high when trying to conceive during the ovulation period. </p>
                            <p class="text-justify">For more information, you can always reach out to experts at Iswarya IVF Fertility &amp; Pregnancy Centre.</p>','1641904120-73719552.jpg','0000-00-00 00:00:00','0000-00-00 00:00:00','0000-00-00 00:00:00');

INSERT INTO tb_situations_details (id, situation_id, title, question, answer, image, created_at, updated_at, deleted_at) VALUES ('2','1','Age & successful pregnancy','Does age plays a crucial role to have a successful pregnancy?','<h4 class="s-head">Does age plays a crucial role to have a successful pregnancy </h4>
                           <p class="text-justify">Yes, age does matter for both women and men who desire to have a family. When it comes to women, age plays a crucial role in pregnancy as it can affect their fertility significantly. With age, the chances of having a baby decrease. The chances are higher if women are younger than 35 years and men younger than 40. </p>
                           <p class="text-justify">You can always connect with specialists at Iswarya IVF Fertility &amp; Pregnancy Centre if you are facing any issues related to the same. </p>','1641904282-44568988.jpg','0000-00-00 00:00:00','0000-00-00 00:00:00','0000-00-00 00:00:00');

INSERT INTO tb_situations_details (id, situation_id, title, question, answer, image, created_at, updated_at, deleted_at) VALUES ('3','1','Changes needed','What are the changes needed to bring in lifestyle to enhance the chances of becoming pregnant?','<h4 class="s-head">What are the changes needed to bring  in  lifestyle to enhance the chances of becoming pregnant?</h4>
                           <p class="text-justify">You need to make some healthy lifestyle changes to enhance the chances of becoming pregnant and eventually delivering a healthy baby. To increase the odds of a successful pregnancy, both men and women should cut down on smoking, caffeine, and alcohol consumption. Not only this, you need to make sure that you consume the right nutrition as well to deliver a healthy baby.</p>
                           <p class="text-justify">You can reach out to professionals at Iswarya IVF Fertility &amp; Pregnancy Centre to gain a better understanding of the same. </p>','1648537716-36314699.jpg','0000-00-00 00:00:00','0000-00-00 00:00:00','0000-00-00 00:00:00');

INSERT INTO tb_situations_details (id, situation_id, title, question, answer, image, created_at, updated_at, deleted_at) VALUES ('4','1','Body Weight & pregnancy','Does weight play a role in pregnancy?','<h4 class="s-head">Does weight play a role in pregnancy?</h4>
                           <p class="text-justify">Yes! If you are planning a pregnancy, it is important that you focus on a healthy diet and exercising regularly. Following this lifestyle can help you boost your fertility, and this can enhance the chance of conceiving. So, you need to maintain a healthy weight to give yourself a good chance of not only becoming pregnant but also having a healthy baby.</p>
                           <p class="text-justify">Consider connecting with a specialist at Iswarya IVF Fertility &amp; Pregnancy Centre to gain better know-how of the same. </p>','1648537854-85603277.jpg','0000-00-00 00:00:00','0000-00-00 00:00:00','0000-00-00 00:00:00');

INSERT INTO tb_situations_details (id, situation_id, title, question, answer, image, created_at, updated_at, deleted_at) VALUES ('5','2','Causes of irregular periods','What causes irregular periods?','<h2 class="s-head">What causes irregular periods? </h2>
                                  <p class="text-justify">Irregular periods are now a part of several women, and the reason behind the same is subtle hormonal imbalance. But, this doesn\'t mean that you are not ovulating. You are going to ovulate every single month, but the timing might vary. So, you need to track the same to enhance the chances of getting pregnant naturally. </p>
                                  <p class="text-justify">If you need more assistance, then you can always knock on the doors of specialists at Iswarya IVF Fertility &amp; Pregnancy Centre and get all the assistance you need to deal with irregular menses.</p>','1648537991-35428427.jpg','0000-00-00 00:00:00','0000-00-00 00:00:00','0000-00-00 00:00:00');

INSERT INTO tb_situations_details (id, situation_id, title, question, answer, image, created_at, updated_at, deleted_at) VALUES ('6','2','Detect ovulation cycle','How to detect ovulation cycle with irregular periods?','<h4 class="s-head">How to detect ovulation cycle with irregular periods? </h4>
                           <p class="text-justify">You need to make a special effort to detect your ovulation cycle if you are suffering from irregular menses. You can consider using an ovulation detector and then take your next step ahead so that the chances of positive results are high. </p>
                           <p class="text-justify">If still, you are not getting the result you are looking for, then you can always consider connecting with a specialist at Iswarya IVF Fertility &amp; Pregnancy Centre for better guidance. </p>','1648538079-50159303.jpg','0000-00-00 00:00:00','0000-00-00 00:00:00','0000-00-00 00:00:00');

INSERT INTO tb_situations_details (id, situation_id, title, question, answer, image, created_at, updated_at, deleted_at) VALUES ('7','2','Needed lifestyle changes','What are the lifestyle changes needed to be made to regulate ovulation?','<h4 class="s-head">What are the lifestyle changes needed to be made to regulate ovulation?</h4>
                           <p class="text-justify">To regular your periods, you just cannot depend on fertility drugs. You must act strictly to change the way you live. You need to have a healthy diet and exercise regularly to maintain a healthy weight. Following the right routine can help you regulate your menses and enhance the chance of timely ovulation. </p>
                           <p class="text-justify">You might always reach out to the experts at Iswarya IVF Fertility &amp; Pregnancy Centre </p>','1648538172-70633681.jpg','0000-00-00 00:00:00','0000-00-00 00:00:00','0000-00-00 00:00:00');

INSERT INTO tb_situations_details (id, situation_id, title, question, answer, image, created_at, updated_at, deleted_at) VALUES ('8','2','Missed period','Is a missed period considered as a part of irregular menses?','<h4 class="s-head">Is a missed period considered as a part of irregular menses?</h4>
                           <p class="text-justify">There are times when a period is late, and it can also be a good reason. So, before you schedule an appointment, you must first check whether you are pregnant or not. If not, then it is a part of irregular menses, and you can consider getting yourself checked by a specialist. </p>
                           <p class="text-justify">Experts at Iswarya IVF Fertility &amp; Pregnancy can assist you with the same at your convenience. </p>','1648538252-95109105.jpg','0000-00-00 00:00:00','0000-00-00 00:00:00','0000-00-00 00:00:00');

INSERT INTO tb_situations_details (id, situation_id, title, question, answer, image, created_at, updated_at, deleted_at) VALUES ('9','2','Menstrual Guidance','When should you see a doctor about your irregular menses?','<h4 class="s-head">When should you see a doctor about your irregular menses?</h4>
                           <p class="text-justify">It\'s better to connect with a gynecologist as and when you are trying to get pregnant, but the results aren\'t going your way because of irregular periods. Running some tests can help them get an understanding of where the problem lies and help you with proper medication that can help you conceive without any hassle.  </p>
                           <p class="text-justify">If  you are looking for assistance, you can always consider connecting with specialists at Iswarya IVF Fertility &amp; Pregnancy Centre. </p>','1648538337-17564960.jpg','0000-00-00 00:00:00','0000-00-00 00:00:00','0000-00-00 00:00:00');

INSERT INTO tb_situations_details (id, situation_id, title, question, answer, image, created_at, updated_at, deleted_at) VALUES ('10','3','Role of age in pregnancy','','<h2 class="s-head">Is age a factor behind multiple failures of pregnancies?  </h2>
                                  <p class="text-justify">Yes! Age is a big factor behind multiple miscarriages. Women older than 35 have a 20% risk of miscarriage, and the ones who are 40 have an 80% chance of failure of pregnancy. So, this shows how age is certainly one of the primary reasons behind pregnancy failure. </p>
                                  <p class="text-justify">To know more, you can always consider booking an appointment at Iswarya IVF Fertility &amp; Pregnancy Centre.</p>','1648539311-6997567.jpg','0000-00-00 00:00:00','0000-00-00 00:00:00','0000-00-00 00:00:00');

INSERT INTO tb_situations_details (id, situation_id, title, question, answer, image, created_at, updated_at, deleted_at) VALUES ('11','3','Pregnancy failures','','<h4 class="s-head">What are the causes of multiple failures of pregnancies? </h4>
                           <p class="text-justify">There are several causes behind multiple failures of pregnancies. Mostly it has been found that the fetus is not developing as expected, and this leads to failure. You need to be very careful in all the trimesters and do as your doctor says to avoid any such situation.</p>
                           <p class="text-justify">For more assistance, you can always connect with the specialist at Iswarya IVF Fertility &amp; Pregnancy Centre.  </p>','1648539403-19948077.jpg','0000-00-00 00:00:00','0000-00-00 00:00:00','0000-00-00 00:00:00');

INSERT INTO tb_situations_details (id, situation_id, title, question, answer, image, created_at, updated_at, deleted_at) VALUES ('12','3','Multiple miscarriages','','<h4 class="s-head">What does not cause multiple miscarriages?</h4>
                           <p class="text-justify">There are several myths revolving around the failure of pregnancies. You must not entertain the myths and boost your stress level. Routine activities like exercising regularly, sexual activities, or even working don\'t lead to miscarriages. There are many other reasons that lead to it that need to be assessed by taking the assistance of a specialist.  </p>
                           <p class="text-justify">This is when you can consider reaching out to Iswarya IVF Fertility and Pregnancy Centre and get all the assistance you need. </p>','1648539477-27420981.jpg','0000-00-00 00:00:00','0000-00-00 00:00:00','0000-00-00 00:00:00');

INSERT INTO tb_situations_details (id, situation_id, title, question, answer, image, created_at, updated_at, deleted_at) VALUES ('13','3','Risk in to multiple miscarriages','','<h4 class="s-head">What are the risks that can lead to multiple miscarriages?</h4>
                           <p class="text-justify">There are several risks that can be the reason behind multiple miscarriages. It can be your age, previous health conditions, problems related to cervical, alcohol issues, weight, and many more. All these aspects can be the reasons that are making you suffer from multiple miscarriages.  </p>
                           <p class="text-justify">So, it is important that you get yourself checked by the specialist at Iswarya IVF Fertility &amp; Pregnancy Centre to gain proper knowledge about the same.</p>','1648539534-45237425.jpg','0000-00-00 00:00:00','0000-00-00 00:00:00','0000-00-00 00:00:00');

INSERT INTO tb_situations_details (id, situation_id, title, question, answer, image, created_at, updated_at, deleted_at) VALUES ('14','3','Prevent miscarriage','','<h4 class="s-head">How to prevent miscarriage?</h4>
                           <p class="text-justify">There is always a way that can help you prevent a failure of pregnancy. All you need to do is to take good care of yourself and your baby. For the same, you must consider opting for regular prenatal care and avoid all the risk factors that lead to miscarriage. You must seek medical attention whenever you are having any kind of issue to avoid the same at the earliest.   </p>
                           <p class="text-justify">Iswarya IVF Fertility &amp; Pregnancy can certainly help you with it. You can always reach out to our specialist and take all the assistance you need to prevent pregnancy failure.  </p>','1648539665-28598730.jpg','0000-00-00 00:00:00','0000-00-00 00:00:00','0000-00-00 00:00:00');

INSERT INTO tb_situations_details (id, situation_id, title, question, answer, image, created_at, updated_at, deleted_at) VALUES ('15','4','Vitro fertilization','','<h2 class="s-head">What is in vitro fertilization? </h2>
                                  <p class="text-justify">When it comes to In vitro fertilization or IVF, it is one of the fertility treatments popular all around the world. It is actually acknowledged as assisted reproductive technology where both sperm and the egg are administered in a lab. This treatment removes the mature female eggs with the use of a needle and then puts the sperm in it with the use of lab facilities. </p>
                                  <p class="text-justify">To know more, you can always consider connecting with the specialists at Iswarya IVF Fertility &amp; Pregnancy Centre.</p>','1648539774-42710083.jpg','0000-00-00 00:00:00','0000-00-00 00:00:00','0000-00-00 00:00:00');

INSERT INTO tb_situations_details (id, situation_id, title, question, answer, image, created_at, updated_at, deleted_at) VALUES ('16','4','Treatment options','','<h4 class="s-head">What are the different fertility treatment options? </h4>
                           <p class="text-justify">There are many treatment options to deal with fertility issues. Your case is assessed by the specialist, and accordingly, the best treatment options are considered. Some of the options that are considered by the specialists are surgery to repair any issues with the reproductive system, IVF, Intracytoplasmic sperm injection, and more. </p>
                           <p class="text-justify">You can consider connecting with the specialists at Iswarya IVF Fertility &amp; Pregnancy Centre and get a better understanding of the treatments as per your needs.  </p>','1648539874-35981417.jpg','0000-00-00 00:00:00','0000-00-00 00:00:00','0000-00-00 00:00:00');

INSERT INTO tb_situations_details (id, situation_id, title, question, answer, image, created_at, updated_at, deleted_at) VALUES ('17','4','Risks associated with treatment','','<h4 class="s-head">What are the risks associated with fertility treatment options?</h4>
                           <p class="text-justify">When it comes to side effects and risks, it completely depends on the kind of fertility treatment you consider for the pregnancy. Every single treatment has its own set of risks, but a few of the common ones are bloating, headache, mood swings, and more.   </p>
                           <p class="text-justify">If you are worried about the same, then you can always consider reaching out to the specialist at Iswarya IVF Fertility &amp; Pregnancy Centre.  </p>','1648539970-24701879.jpg','0000-00-00 00:00:00','0000-00-00 00:00:00','0000-00-00 00:00:00');

INSERT INTO tb_situations_details (id, situation_id, title, question, answer, image, created_at, updated_at, deleted_at) VALUES ('18','4','Success rate','','<h4 class="s-head">What is the success rate of fertility treatments?</h4>
                           <p class="text-justify">The success rate of the fertility treatment completely depends on the treatment that is being considered for your issue. Not only this, but it also depends on your age, how long you are facing the respective issue, and your health conditions. So, it varies from one person to another.  </p>
                           <p class="text-justify">To get a better understanding of the same, you can always reach out to experts at Iswarya IVF Fertility &amp; Pregnancy Centre and assess the chances of your success a lot more clearly. </p>','1648540046-5076264.jpg','0000-00-00 00:00:00','0000-00-00 00:00:00','0000-00-00 00:00:00');

INSERT INTO tb_situations_details (id, situation_id, title, question, answer, image, created_at, updated_at, deleted_at) VALUES ('19','4','Fertility treatment fails','','<h4 class="s-head">What if the fertility treatment fails?</h4>
                           <p class="text-justify">We all have high hopes when the fertility treatment is initiated, but, unfortunately, things might not turn out the way you want. There is a high probability of it not going the way you are thinking so, you need to be prepared for the same and deal with it while being emotionally and mentally strong. Taking the assistance of experts can certainly make things easy for you to understand what needs to be done next. </p>
                           <p class="text-justify">You can always connect with the specialists at Iswarya IVF Fertility &amp; Pregnancy Centre to get complete know-how of the same.  </p>','1648540149-19095233.jpg','0000-00-00 00:00:00','0000-00-00 00:00:00','0000-00-00 00:00:00');

INSERT INTO tb_situations_details (id, situation_id, title, question, answer, image, created_at, updated_at, deleted_at) VALUES ('20','5','PCOS?','','<h2 class="s-head">What is PCOS? </h2>
                                  <p class="text-justify">When it comes to PCOS or Polycystic ovarian syndrome, it is acknowledged as one of the most common causes behind female fertility issues. It has affected more than 5 million women around the world. But, this doesn\'t mean that you cannot get pregnant if you are suffering from PCOS.  </p>
                                  <p class="text-justify">You can connect with the specialist at Iswarya IVF Fertility &amp; Pregnancy Centre and get all the understanding about the same!</p>','1648540253-97624574.jpg','0000-00-00 00:00:00','0000-00-00 00:00:00','0000-00-00 00:00:00');

INSERT INTO tb_situations_details (id, situation_id, title, question, answer, image, created_at, updated_at, deleted_at) VALUES ('21','5','Chances of pregnancy in PCOS','','<h4 class="s-head">What are the lifestyle changes one needs to enhance their chances of pregnancy in PCOS? </h4>
                           <p class="text-justify">It is important that they have to follow a healthy diet and quite all the stuff related to alcohol to enhance the chances of pregnancy. There must not be any smoking and drinking involved in your diet. Following a healthy routine can always help you improve your chances of becoming pregnant, even when suffering from PCOS. </p>
                           <p class="text-justify">Iswarya IVF Fertility &amp; Pregnancy Centre is always available to help you with it. Connect with our specialist and enhance your lifestyle without any hassle. </p>','1648540375-15156393.jpg','0000-00-00 00:00:00','0000-00-00 00:00:00','0000-00-00 00:00:00');

INSERT INTO tb_situations_details (id, situation_id, title, question, answer, image, created_at, updated_at, deleted_at) VALUES ('22','5','PCOS- healthy pregnancy','','<h4 class="s-head">How to have healthy pregnancies with PCOS? </h4>
                           <p class="text-justify">The first thing that needs to be done is regulate the menses. Fortunately, you can take the assistance of several treatments available to have healthy pregnancies even when you are suffering from PCOS. The doctor can assess your condition and accordingly guide you with medication that can not only regulate your menses but also enhance the chances of a healthy pregnancy.   </p>
                           <p class="text-justify">Specialists at Iswarya IVF Fertility &amp; Pregnancy Centre can always help you with the right medication to have a healthy pregnancy with PCOS.  </p>','1648540457-77713244.jpg','0000-00-00 00:00:00','0000-00-00 00:00:00','0000-00-00 00:00:00');

INSERT INTO tb_situations_details (id, situation_id, title, question, answer, image, created_at, updated_at, deleted_at) VALUES ('23','5','Weight issue & pcos','','<h4 class="s-head">Is weight an issue while suffering PCOS? </h4>
                           <p class="text-justify">Yes! It has been seen that most women with PCOS syndrome are obese, and this is why they are finding it difficult to get pregnant. So, it is important that they work out regularly and follow a very healthy diet that can help them lose the extra fat and maintain proper weight. Doing the same can certainly enhance the chances of pregnancy and help you deliver a healthy baby.  </p>
                           <p class="text-justify">You can always take the assistance of Iswarya IVF Fertility &amp; Pregnancy Centre as you get experts to assist you in bidding adieu to the extra weight. </p>','1648540608-79131326.jpg','0000-00-00 00:00:00','0000-00-00 00:00:00','0000-00-00 00:00:00');

INSERT INTO tb_situations_details (id, situation_id, title, question, answer, image, created_at, updated_at, deleted_at) VALUES ('24','5','Healthy diet','','<h4 class="s-head">What is an ideal fertility-friendly eating routine to be followed for PCOS?</h4>
                           <p class="text-justify">It is important to follow a good and healthy diet to enhance the chances of pregnancy for PCOS women.  A few of the suggestions that can help you are: </p>
                           <ul class="flower list-unstyled mb-0">
                           <li>Having a bigger breakfast and lighter dinner.</li>
                           <li>Make sure your plat has more greens and proteins.</li>
                           <li>Complex carbs can be a part of your diet.</li>
                           <li>Combine your cheat day with healthy fats to curb the sugar spike. </li>

                           </ul>
                           <p class="text-justify">To know more, you can always reach out to specialists at Iswarya IVF Fertility &amp; Pregnancy Centre and get all the assistance on the same.  </p>','1648540733-11170752.jpg','0000-00-00 00:00:00','0000-00-00 00:00:00','0000-00-00 00:00:00');


