INSERT INTO tb_training_page (id, banner_section, fellowship_section, embryology_section, meta_title, meta_desc, created_at, updated_at, deleted_at) VALUES ('1','{"banner_image":"1647423327.jpg","title":"Training","description":"A thorough course that will provide you with in-depth knowledge and experience in all aspects of infertility treatment and IVF. In our well-equipped Embryology lab, we provide advanced instructions.","banner_btn_name":"Apply","banner_btn_link":"#co-form"}','{"fellowship_title":"Fellowship Reproductive Medicine","fellowship_section1":"<h2 class=\"s-head\">Course Description<\/h2>\r\n\r\n                <p>A comprehensive course that will provide you with the in-depth knowledge and experience in all aspects of infertility treatment and IVF. Infertility management, ultrasonography, IVF stimulation, egg retrieval, laparoscopy, and foetal medicine will be covered. There are excellent library facilities available. Also, the institution will provide candidate fellowship certificate once they have completed the programme.\r\n\r\n                <\/p>\r\n\r\n                <ol class=\"flower list-unstyled mb-0\">\r\n\r\n                    <li>\r\n\r\n                        <h6>Course Duration<\/h6>\r\n\r\n                        <span class=\"d-block\">1 year <\/span>\r\n\r\n\r\n\r\n\r\n                    <\/li>\r\n\r\n                    <li>\r\n\r\n                        <h6>Entry Requirements<\/h6>\r\n\r\n                        <span class=\"d-block\">2 Batches-January\/ July Centers- Coimbatore <\/span>\r\n\r\n                        <span class=\"d-block\">4 candidates per batch<\/span>\r\n\r\n\r\n\r\n                    <\/li>\r\n\r\n                   \r\n\r\n                <\/ol>","fellowship_section2":"<h2 class=\"s-head\">Iswarya fellowship contact<\/h2>\r\n                 <p>We are ready to assist you, If you have any queries regarding Iswarya IVF Fellowship program.\r\n                <\/p>\r\n\r\n                <ul class=\"list-unstyled mb-0\">\r\n\r\n                    <li>\r\n\r\n                       <h6>Fellowship Program Director <\/h6>\r\n                       <span class=\"d-block span\"><strong>Dr.Reshma Shree A <\/strong><\/span>\r\n                       <span class=\"d-block span\">MS(OG), FRM, FMAS, MMAS<\/span>\r\n                       <span class=\"d-block span\"><strong>Mail-To:<\/strong> info@iswaryaivf.com<\/span>\r\n                       <span class=\"d-block span\"><strong>Phone Number:<\/strong> +91 7598229099<\/span>\r\n\r\n\r\n\r\n                    <\/li>\r\n\r\n           \r\n                <\/ul>"}','{"embryology_image":"70221647423327.jpg","embryology_title":"Test","embryology_section1":"<h2 class=\"common-head\">Embryology Training<\/h2>\r\n\r\n                <p>In our well-equipped Embryology lab, we provide advanced training with clear cut instructions. Renowned embryologists, andrologists, and fertility specialists will instruct the trainees.\r\n\r\n                <\/p>\r\n\r\n                <ul class=\"list-unstyled mb-0\">\r\n\r\n                    <li>\r\n\r\n                        <h6>Course Duration <\/h6>\r\n\r\n                       <span class=\"d-block span\">Advance course - 1 year  <\/span>\r\n                       <span class=\"d-block span\">Basic course \u2013 6 months<\/span>\r\n                       <span class=\"d-block span\"><strong>Mail-To:<\/strong> info@iswaryaivf.com<\/span>\r\n                       <span class=\"d-block span\"><strong>Phone Number:<\/strong> +91 9345965021<\/span>\r\n\r\n                   <\/li>\r\n                <\/ul>\r\n\r\n                 <h3 class=\"s-head\">Eligibility Criteria for candidates who would like to join the course<\/h3>\r\n                 <ol class=\"flower list-unstyled mb-0\">\r\n\r\n                    <li> BSC <\/li>\r\n                    <li> MSC or Any other life science background <\/li>\r\n                    <li> BDS <\/li>\r\n                    <li> MBBS <\/li>\r\n                    <li> MD <\/li>\r\n                <\/ol>"}','Best IVF Training Center in India | Dr. Aravind\'s IVF Fertility & Pregnancy Centre','A thorough course that will provide you with in-depth knowledge and experience in all aspects of infertility treatment and IVF. Apply for IVF Training now!','2022-10-12 05:53:04','2022-03-16 06:55:53','2022-03-16 06:55:53');


