INSERT INTO tb_treatments (id, category_id, name, sub_title, link, image, short_description, description, description2, treat_ourservice, meta_title, meta_desc, created_at, updated_at, deleted_at) VALUES ('1','1','Natural + OI','Ovulation Induction Natural Fertility Treatment','naturalplusoi','1638511320-23600705.jpg','Dr. Aravind\'s IVF Fertility & Pregnancy Centre Treatment will help you with natural ovulation induction treatment for your fertility issues. This treatment is basically for women who are not able to ovulate.','<p class="text-justify">Dr. Aravind\'s IVF Fertility &amp; Pregnancy Centre Treatment will help you with natural ovulation induction treatment for your fertility issues. This treatment is used to help for women who are not able to ovulate. Yes, a large number of women experience irregular ovulation or missed periods. The reason behind this issue is acknowledged as Polycystic Ovary Syndrome.</p>
<p class="text-justify">Dr. Aravind\'s IVF Fertility &amp; Pregnancy Centre will help you out of the trouble if you are suffering the same issue. All you need to do is to book your appointment with us online and we will get you treated with the best of solution via Ovulation Induction.</p>','<p class="text-justify">So, you must not hesitate and get connected immediatey with our support executives now to get your appointment fixed. Our experts will help you get back to normal by resolving the ovulation issue you are facing. You will never be dissatisfied with our services! Now is the right time to connect!<br><br><br></p>','<li>This process will involve the use of clomifene tablets.</li><li>If all works well, you will be able to conceive.</li><li>FSH injections can also be used to take the treatment ahead instead of clomifene tablets.</li><li>If not, we can help you with IUI treatment, which can produce excellent results.</li><li>The regular scan will be scheduled to monitor how your ovaries are responding to this process.<br></li>','Ovulation Induction Natural Treatment (OI) Fertility Center in India | Dr. Aravind\'s IVF Fertility & Pregnancy Centre','Dr. Aravind\'s IVF Fertility & Pregnancy Centre Treatment will help you with natural ovulation induction treatment for your fertility issues. Get connected immediately with our support executives now to get your appointment fixed.','2021-12-03 11:32:00','2022-07-10 23:11:02','2022-07-10 23:11:02');

INSERT INTO tb_treatments (id, category_id, name, sub_title, link, image, short_description, description, description2, treat_ourservice, meta_title, meta_desc, created_at, updated_at, deleted_at) VALUES ('2','0','IUI','Intrauterine Insemination (IUI) Fertility Treatment','iui','1641933866-77813117.jpg','Dr. Aravind\'s IVF Fertility & Pregnancy Centre is here to help you with another result-oriented treatment of Intrauterine Insemination (IUI). This is basically a process where our experts will be preparing sperms and then get that deposited in a woman’s uterus.','<p class="text-justify">Dr. Aravind\'s IVF Fertility &amp; Pregnancy Centre is here to help you with another result-oriented treatment of Intrauterine Insemination (IUI). This is basically a process where our experts will be collecting sperms and then get that deposited in a woman’s uterus. This procedure yielded great outcomes and assisted a large number of people in becoming parents.</p>
<p class="text-justify">There is no discomfort attached to this methodology. This treatment has an excellent success rate and will certainly give you the best of experience in relishing the dream of parenthood. There are a number of different methods followed while providing this service like Natural cycle, Super Ovulation cycle, Clomid cycle, Donor Sperm, and Ovulation induction cycle. </p>','<p class="text-justify">So, this is a very simple process that can help you live your dream of moving into parenthood world. Just get connected and fix your appointment with us now! We will never let you down!</p>','<li>

                                This treatment will be initiated with the continuous monitoring of the ovulation cycle through a urine test, blood tests, and ultrasound.

                                </li>

                                <li>

                                If required, medication will also be tried to check the ovulation cycle.

                                </li>

                                <li>After getting the ovulation cycle result, we will initiate with the process of collecting top quality semen.</li>

                                <li>With the use of speculum and catheter, we will transfer the sperm to the cervix.

                                </li>','Intrauterine Insemination (IUI) Treatment Fertility Center in India | Dr. Aravind\'s IVF Fertility & Pregnancy Centre','Dr. Aravind\'s IVF Fertility & Pregnancy Centre is here to help you with another result-oriented treatment of Intrauterine Insemination (IUI). Get connected immediately with our support executives now to get your appointment fixed.','2022-01-11 20:44:26','2022-01-11 20:44:26','2022-01-11 20:44:26');

INSERT INTO tb_treatments (id, category_id, name, sub_title, link, image, short_description, description, description2, treat_ourservice, meta_title, meta_desc, created_at, updated_at, deleted_at) VALUES ('3','0','IVF','In Vitro Fertilization (IVF) Fertility Treatment','ivf','1648722252-51172077.jpg','','','','<li>

                                  The ovaries of the patient will be stimulated first. This will be done with the use of fertility drugs.
                                </li>

                                <li>

                                   The embryos are then cultured for the next 4 to 5 days.

                                </li>

                                <li>This will exclusively produce a number of mature eggs. </li>

                                <li>Finally, one of the embryos cultured is moved back into the uterus.

                                </li>
                                <li>The produced eggs will be collected to get it fertilized with the sperm of the partner.</li>','In vitro fertilization (IVF) Treatment Fertility Center in India | Dr. Aravind\'s IVF Fertility & Pregnancy Centre','Dr. Aravind\'s IVF Fertility & Pregnancy Centre is here to help you with In vitro fertilization (IVF) Treatment. Get connected immediately with our support executives now to get your appointment fixed.','2022-03-31 10:24:12','2022-03-31 10:24:12','2022-03-31 10:24:12');

INSERT INTO tb_treatments (id, category_id, name, sub_title, link, image, short_description, description, description2, treat_ourservice, meta_title, meta_desc, created_at, updated_at, deleted_at) VALUES ('4','0','ICSI','ICSI Fertility Treatment','icsi','1648722707-45114198.jpg','','<p class="text-justify">Dr. Aravind\'s IVF Fertility &amp; Pregnancy Centre is here to help you with the ICSI process which can be a big help for you to live your dream of becoming a parent. ICSI is one of the most successful treatment processes which has helped a number of individuals with their needs of becoming a parent. Our specialists will assess each and every challenge that you face in the entire process and work on it accordingly. It\'s a complicated process but our specialists will not let you down and give you the result as per your expectations.</p>
<p class="text-justify">All you need to do is to reach out to our team and let us help you live the parenthood life. You just need to fix your appointment online and our support will make it easy for you with thoroughly approved ICSI Treatment:</p>','','<li>

                                To hold the egg in one place, a special instrument is taken into consideration.

                                </li>

                                <li>

                                The sperm is slowly injected into the egg, and the needle is removed, leaving the sperm behind.

                                </li>

                                <li>The egg is very small. A needle-like tool will be used to hold a single healthy sperm. </li>

                                <li>The eggs injected with the sperm is then stored in an incubator overnight. 

                                </li>
                                <li>The needle holding the sperm is then injected in the egg through the outer coating.</li>
                                <li>It will be checked next morning to see if there are any signs of fertilisation. </li>','Intracytoplasmic Sperm Injection(ICSI) Treatment fertility Center in India | Dr. Aravind\'s IVF Fertility & Pregnancy Centre','Dr. Aravind\'s IVF Fertility & Pregnancy Centre is here to help you with the ICSI process which can be a big help for you to live your dream of becoming a parent. Get connected immediately with our support executives now to get your appointment fixed.','2022-03-31 10:31:47','2022-03-31 10:31:47','2022-03-31 10:31:47');

INSERT INTO tb_treatments (id, category_id, name, sub_title, link, image, short_description, description, description2, treat_ourservice, meta_title, meta_desc, created_at, updated_at, deleted_at) VALUES ('5','0','IMSI','IMSI Fertility Treatment','imsi','1648722909-5976761.jpg','','<p class="text-justify">Dr. Aravind\'s IVF Fertility &amp; Pregnancy Centre will let your dream of becoming a parent come true with Intracytoplasmic morphologically selected sperm injection (IMSI) program. This procedure is essentially an ICSI variation in which a high-powered microscope is used to pick the healthiest sperm. It enhances the chances of even more of a successful pregnancy when compared to ICSI.
</p>
<p class="text-justify">
It is important to check with the shape of sperm with thorough detail as it helps in the process of pregnancy quite significantly. This will reduce the chances of miscarriage and it has been seen that selecting a better-shaped sperm has resulted in excellent pregnancy results. So, contact Iswarya IVF Center today and offer yourself the gift of parenthood with IMSI.</p>','','<li>

                                   In our IMSI treatment, we will be using a high power light microscope. It will magnify the picture of the sperm 6000 times. 

                                </li>

                                <li>

                                   This will give a better idea to the embryologist and help them detect healthy sperm which has more subtle structural alterations that are not detectable in a normal microscope.

                                </li>

                                <li>After this, sperm with normal shaped nuclei are selected for further process. </li>','Intracytoplasmic morphologically selected sperm injection (IMSI) Treatment Fertility Center in India | Dr. Aravind\'s IVF Fertility & Pregnancy Centre','Dr. Aravind\'s IVF Fertility & Pregnancy Centre is here to help you with the Intracytoplasmic morphologically selected sperm injection (IMSI) program. Get connected immediately with our support executives now to get your appointment fixed.','2022-03-31 10:35:09','2022-03-31 10:35:09','2022-03-31 10:35:09');

INSERT INTO tb_treatments (id, category_id, name, sub_title, link, image, short_description, description, description2, treat_ourservice, meta_title, meta_desc, created_at, updated_at, deleted_at) VALUES ('6','0','PGS','PGS Fertility Treatment','pgs','1648723092-49935058.jpg','','<p class="text-justify">Dr. Aravind\'s IVF Fertility &amp; Pregnancy Centre treatment has all the answers for you if you are suffering from infertility issues. Yes, our Preimplantation Genetic Screening (PGS) treatments will help you deal with this situation in the most professional way. It is a specialized technique that is taken into consideration for embryos testing as it helps in diagnosing chromosomal abnormality.

</p>
<p class="text-justify">
So, if you wish to enter the world of parenthood, simply contact our customer service representatives and let us assist you in getting out of this position. Iswarya IVF would never let you down and will make certain that you get the outcomes you desire. Our experts will examine your situation on an individual basis and advise you on the best course of action to help you turn the tide and enjoy being a parent.</p>','<p class="text-justify">
So, get connected now and experience the difference as we will help you live the parenthood life overcoming all the challenges with PGS treatment.</p>','<li>

                                IVF treatment will be the first step in the procedure. This will be done to develop embryos. 

                                </li>

                                <li>

                                After this process, genetic analysis will be performed around the 5th day of embryo development. 

                                </li>

                                <li>Next, we will examine the material expelled from the embryo to assess if there are any losses or gains in the chromosome numbers. </li>','Preimplantation genetic screening (PGS) Treatment Fertility Center in India | Dr. Aravind\'s IVF Fertility & Pregnancy Centre','Dr. Aravind\'s IVF Fertility & Pregnancy Centre is here to help you with Preimplantation Genetic Screening (PGS) treatments that will help you to deal with infertility issues. Get connected immediately with our support executives now to get your appointment fixed.','2022-03-31 10:38:12','2022-03-31 10:38:12','2022-03-31 10:38:12');

INSERT INTO tb_treatments (id, category_id, name, sub_title, link, image, short_description, description, description2, treat_ourservice, meta_title, meta_desc, created_at, updated_at, deleted_at) VALUES ('7','0','PGD','PGD Fertility Treatment','pgd','1648723266-83222541.jpg','','<p class="text-justify">Dr. Aravind\'s IVF Fertility &amp; Pregnancy Centre is here to help you with the best of treatments that can help you live your parenthood life without much of a trouble. Our PGD (preimplantation genetic diagnosis) treatment has helped individuals to become parents. So, you can reach out our experts and let them help you relish the dream of parenthood. We will never let you down and make you overcome all the challenges with this treatment procedure.
</p>
<p class="text-justify">This procedure of PGD exclusively allows embryo screening. This is exclusively done for particular genetic traits. This is done before an embryo gets implanted in the uterus of the patients. It will assess if your embryo is affected by any disease or not and design the strategy accordingly and help you become a parent to a beautiful baby.</p>','<p class="text-justify">This process will play a huge role in helping one get pregnant and live the parenthood life. So, what is making you think so long, just get connected to our team now for excellent results!</p>','<li>

                                  At first, the patients need to commence in vitro fertilization (IVF) process so that they can process pre-embryos.

                                </li>

                                <li>

                                  These embryos will be available for testing which comes in the next step.
                                </li>

                                <li>Before the transfer, the cells acknowledged as blastomeres are expelled from the respective pre-embryos. This helps in dealing with abnormalities. </li>
                                <li>After the assessment, only the normal ones are transferred back.</li>','Pre-implantation genetic diagnosis (PGD) Treatment Fertility Center in India | Dr. Aravind\'s IVF Fertility & Pregnancy Centre','Dr. Aravind\'s IVF Fertility & Pregnancy Centre is here to help you with Preimplantation Genetic Diagnosis (PGD) with the best of treatment that has helped individuals to become parents. Get connected immediately with our support executives now to get your appointment fixed.','2022-03-31 10:41:06','2022-03-31 10:41:06','2022-03-31 10:41:06');

INSERT INTO tb_treatments (id, category_id, name, sub_title, link, image, short_description, description, description2, treat_ourservice, meta_title, meta_desc, created_at, updated_at, deleted_at) VALUES ('8','0','Surrogacy','Surrogacy Fertility Treatment','surrogacy','1648723512-84556851.jpg','','<p class="text-justify">Are you wondering will you be able to relish the life of being a parent? Iswarya IVF Center is here to make things easier for you. Our surrogacy program will not leave you down and make sure that you are able to live your dream by overlapping all the challenges. Because your health prevents you from bearing a child on your own, a surrogacy programme will allow other women to carry your child for you.
</p>
<p class="text-justify">The mother who will be helping you will be under contract to get implanted with the respective embryos developed from the client couple. This will help her become pregnant. So, you can trust Iswarya IVF Center and make it easy for yourself to have a chance of becoming a parent.</p>','<p class="text-justify">So, you will eventually have your own child by booking your appointment with us. Do not wait for long and fix an appointment with Iswarya IVF Center now!</p>','<li> The partners will thoroughly be assessed by our fertility experts.
                                </li>

                                <li>

                                    Sperm will be injected into the eggs for the fertilization process.

                                </li>
                                <li>An IVF cycle will be infused. This will be done to stimulate ovulation.</li>

                                <li>Embryos grow in vitro. Embryo or blastocyst transfer is taken into consideration to move the embryos to the uterus of a surrogate mother. </li>
                                <li>Ultrasound will confirm the development of ovarian follicles. The eggs will be checked by our specialists.</li>','Surrogacy Treatment Fertility Center in India | Dr. Aravind\'s IVF Fertility & Pregnancy Centre','Dr. Aravind\'s IVF Fertility & Pregnancy Centre is here to help you with Surrogacy Treatment will not leave you down and make sure that you are able to live your dream by overlapping all the challenges. Get connected immediately with our support executives now to get your appointment fixed.','2022-03-31 10:45:12','2022-03-31 10:45:12','2022-03-31 10:45:12');

INSERT INTO tb_treatments (id, category_id, name, sub_title, link, image, short_description, description, description2, treat_ourservice, meta_title, meta_desc, created_at, updated_at, deleted_at) VALUES ('9','0','Azoospermia','Azoospermia Fertility Treatment','azoospermia','1648723834-54591546.jpg','','<p class="text-justify">Dr. Aravind\'s IVF Fertility &amp; Pregnancy Centre is here to help you with the best of solutions which will make things happening to live a parenthood life. Azoospermia fertility treatment has helped a number of people who are suffering from infertility related issues and helped them with excellent results. Azoospermia is basically the cause of low or no sperm generation. Our experts will help you get this resolved and enhance the chances of you becoming a parent.
</p>
<p class="text-justify">We have been in this field for a long period of time and have helped individuals get rid of all the challenges they are facing during the entire process. To deal with Azoospermia, our experts have acquired experience to assist you with better results. Make a reservation right now!</p>','<p class="text-justify">This process will certainly help you get the chance of becoming a parent again. All you have to do is contact our professionals, and Iswarya IVF Center will make things easy for you and ensure that you achieve your goal of being a proud parent.</p>','<li>

                                The doctor experts will investigate the causes of low sperm count.

                                </li>

                                <li>

                                The prime reason behind this is that two ends of the vas are not connected and have a blockage.

                                </li>
                                <li>The experts will work in the process of its reconnection.</li>','Azoospermia Treatment Fertility Center in India | Dr. Aravind\'s IVF Fertility & Pregnancy Centre','Dr. Aravind\'s IVF Fertility & Pregnancy Centre is here to help you with Azoospermia fertility treatment has helped a number of people who are suffering from infertility-related issues. Get connected immediately with our support executives now to get your appointment fixed.','2022-03-31 10:50:34','2022-03-31 10:50:34','2022-03-31 10:50:34');

INSERT INTO tb_treatments (id, category_id, name, sub_title, link, image, short_description, description, description2, treat_ourservice, meta_title, meta_desc, created_at, updated_at, deleted_at) VALUES ('10','0','Egg Donor','Egg Donor Fertility Treatment','eggdonor','1648724339-21212085.jpg','','<p class="text-justify">There are many woman who are above the 40s and have not conceived because of various reasons. Other treatments might not have worked and you might be looking for ways that can work wonders for you. We at, Iswarya IVF will help you with the best of treatment in the form of an egg donor. Yes, it will increase the chances of you becoming pregnant even more. It has helped a number of individuals with the best of results.
</p>
<p class="text-justify">So, you must not hesitate and get your appointment fixed now and we will assess the challenges and design the best of approach and make sure that you have your dream of being parents come true.</p>','<p class="text-justify">This process will certainly help you to get the results you are looking for being parents. Our specialists will always be on your side and make sure that you avail complete value for money service.</p>','<li>

                                    At first, we will initiate with the screening of egg donor application.

                                </li>

                                <li>

                                    Next, we will initiate the process of Endometrial Lining Development.

                                </li>
                                <li>After that, we\'ll look for a compatible egg donor.</li>
                                <li>Our specialists will next move ahead with triggering ovulation of egg donor and then take it ahead to Egg Retrieval.</li>
                                <li>We will stop ahead with the process of Ovarian Stimulation and suppression of the respective egg donor.</li>
                                <li>Next, we will move ahead with fertilization and after this, we will stepping ahead towards embryo transfer.</li>','Egg Donor Treatment Fertility Center in India | Dr. Aravind\'s IVF Fertility & Pregnancy Centre','Dr. Aravind\'s IVF Fertility & Pregnancy Centre is here to help you with Egg Donor fertility treatment will increase the chances of you becoming pregnant even more. Get connected immediately with our support executives now to get your appointment fixed.','2022-03-31 10:58:59','2022-03-31 10:58:59','2022-03-31 10:58:59');

INSERT INTO tb_treatments (id, category_id, name, sub_title, link, image, short_description, description, description2, treat_ourservice, meta_title, meta_desc, created_at, updated_at, deleted_at) VALUES ('11','0','Andrology','Andrology Fertility Treatment','andrology','1648724690-91076880.jpg','','<p class="text-justify">Andrology treatment has helped a number of individuals whenever they are facing issues. Our specialists are available all the way by your side to help you with complete assistance in dealing with this situation. Andrology treatment will help the infertile couple to get over all the challenges they are facing and exclusively succeed in becoming a parent. It is difficult for them but we always make it possible for them with our range of solutions we have in store for you.</p>
<p class="text-justify">Our affordable fertility programs will be designed as per the issues you are having and make sure that it helps you with the best of results. So, what\'s keeping you up at night? Just tell our specialists what\'s on your mind, and we\'ll make sure you\'re taken care of.</p>','<p class="text-justify">So, your chances of becoming a parent will undoubtedly increase; all you need to do is communicate with our support team, and we will develop the finest solution in the shape of Andrology and that too at very reasonable rate.</p>','<li>

                                Our andrology laboratory will diagnose semen thoroughly.

                                </li>

                                <li>

                                We will be serving the needs of our patients and general practitioners. 

                                </li>
                                <li>We will provide you with the greatest solution that will provide you desired outcome.</li>','Andrology Treatment Fertility Center in India | Dr. Aravind\'s IVF Fertility & Pregnancy Centre','Dr. Aravind\'s IVF Fertility & Pregnancy Centre is here to help you with Andrology fertility treatment is for who are facing and exclusively succeed in becoming a parent. Get connected immediately with our support executives now to get your appointment fixed.','2022-03-31 11:04:50','2022-03-31 11:04:50','2022-03-31 11:04:50');


CREATE TABLE `tb_users` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `group_id` int(6) DEFAULT NULL,
  `username` varchar(100) NOT NULL,
  `password` varchar(64) NOT NULL,
  `email` varchar(100) NOT NULL,
  `first_name` varchar(50) DEFAULT NULL,
  `last_name` varchar(50) DEFAULT NULL,
  `avatar` varchar(100) DEFAULT NULL,
  `active` tinyint(1) unsigned DEFAULT NULL,
  `login_attempt` tinyint(2) DEFAULT '0',
  `last_login` datetime DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NULL DEFAULT NULL,
  `reminder` varchar(64) DEFAULT NULL,
  `activation` varchar(50) DEFAULT NULL,
  `remember_token` varchar(100) DEFAULT NULL,
  `last_activity` int(20) DEFAULT NULL,
  `config` text,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=3 DEFAULT CHARSET=utf8;


